                            roles_norm = {str(x).strip().lower() for x in r}
                        except Exception:
                            roles_norm = set()
                        return role_norm in roles_norm

            # Unknown structure: fall back to assignment being sufficient
            return True

        # Assigned without role details: grant access
        return True

    # All other roles are not permitted
    return False


def view_patient_record(staff_id: str, staff_role: str, patient_record_id: str):
    """
    Retrieve a patient's medical record if the staff member has appropriate access.

    Returns:
      - medical data (e.g., string) if authorized
      - an error message string otherwise
    """
    # Ensure the global store exists
    try:
        records = PATIENT_RECORDS  # type: ignore[name-defined]
    except NameError:
        return "Error: patient records unavailable"

    record = records.get(patient_record_id)
    if record is None:
        return "Error: patient record not found"

    if has_access(staff_id, staff_role, patient_record_id):
        return record.get("medical_data")
    return "Error: insufficient permissions"

